import React, { useState, useEffect } from 'react';
import { Header } from './Header';
import { AddTodoForm } from './AddTodoForm';
import { TodoList } from './TodoList';
import { ConfirmationModal } from './ConfirmationModal';
import * as apiClient from './apiClient';

export const TodoApp = () => {
  const [todos, setTodos] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [todoToDelete, setTodoToDelete] = useState(null);

  useEffect(() => {
    apiClient.fetchTodos()
      .then(data => {
        setTodos(data);
        setLoading(false);
      })
      .catch(err => {
        setError('Failed to fetch todos.');
        setLoading(false);
      });
  }, []);

  const handleAddTodo = async (newTodo) => {
    try {
      const addedTodo = await apiClient.createTodo(newTodo);
      setTodos([addedTodo, ...todos]);
    } catch (err) {
      setError('Failed to add todo.');
    }
  };

  const handleToggleComplete = async (id, completed) => {
    try {
      const updatedTodo = await apiClient.updateTodo(id, { completed });
      setTodos(todos.map(todo => todo.id === id ? updatedTodo : todo));
    } catch (err) {
      setError('Failed to update todo.');
    }
  };

  const openDeleteModal = (id) => {
    setTodoToDelete(id);
    setIsModalOpen(true);
  };

  const closeDeleteModal = () => {
    setTodoToDelete(null);
    setIsModalOpen(false);
  };

  const handleConfirmDelete = async () => {
    if (todoToDelete) {
      try {
        await apiClient.deleteTodo(todoToDelete);
        setTodos(todos.filter(todo => todo.id !== todoToDelete));
        closeDeleteModal();
      } catch (err) {
        setError('Failed to delete todo.');
        closeDeleteModal();
      }
    }
  };

  return (
    <div className="bg-slate-100 min-h-screen font-sans flex items-center justify-center">
      <div className="bg-white shadow-lg rounded-lg p-6 w-full max-w-2xl mx-4">
        <Header />
        <AddTodoForm onAdd={handleAddTodo} />
        {loading && <p className="text-slate-500 text-center mt-4">Loading...</p>}
        {error && <p className="text-red-500 text-center mt-4">{error}</p>}
        {!loading && !error && (
          <TodoList 
            todos={todos} 
            onToggle={handleToggleComplete} 
            onDelete={openDeleteModal} 
          />
        )}
      </div>
      <ConfirmationModal 
        isOpen={isModalOpen}
        onClose={closeDeleteModal}
        onConfirm={handleConfirmDelete}
      />
    </div>
  );
};

