    <div className="flex items-start p-4 bg-slate-50 rounded-md border border-slate-200 group">
      <input 
        type="checkbox" 
        checked={todo.completed}
        onChange={() => onToggle(todo.id, !todo.completed)}
        className="mt-1 h-5 w-5 rounded border-gray-300 text-blue-600 focus:ring-blue-500"
      />
      <div className={`flex-grow mx-4 ${todo.completed ? 'line-through text-slate-400' : 'text-slate-800'}`}>
        <p className="font-medium">{todo.title}</p>
        <p className="text-sm text-slate-600 ${todo.completed ? 'text-slate-400' : ''}`}>{todo.description}</p>
      </div>
      <button onClick={() => onDelete(todo.id)} className="text-red-400 hover:text-red-600 opacity-0 group-hover:opacity-100 transition-opacity">
        <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
